@@ -105,7 +105,16 @@ final class YoutubeThrottlingParameterUtils {
              */
             Pattern.compile("\\.get\\(\"n\"\\)\\)&&\\(" + SINGLE_CHAR_VARIABLE_REGEX
                     + "=(" + MULTIPLE_CHARS_REGEX + ")(?:" + ARRAY_ACCESS_REGEX + ")?\\("
-                    + SINGLE_CHAR_VARIABLE_REGEX + "\\)")
+                    + SINGLE_CHAR_VARIABLE_REGEX + "\\)"),
+
+            /*
+             * Matches variants where "n" is accessed via a variable (often String.fromCharCode(110)):
+             *
+             * .get(b))&&(c=BDa[0](c)
+             */
+            Pattern.compile("\\.get\\(" + SINGLE_CHAR_VARIABLE_REGEX + "\\)\\)&&\\("
+                    + SINGLE_CHAR_VARIABLE_REGEX + "=(" + MULTIPLE_CHARS_REGEX + ")(?:"
+                    + ARRAY_ACCESS_REGEX + ")?\\(" + SINGLE_CHAR_VARIABLE_REGEX + "\\)")
     };
     // CHECKSTYLE:ON

@@ -131,6 +140,38 @@ final class YoutubeThrottlingParameterUtils {
     private YoutubeThrottlingParameterUtils() {
     }

+    /**
+     * Fallback extraction for the throttling parameter deobfuscation function name.
+     *
+     * <p>We try to find a call site that looks like "someFn(...get('n')...)" or
+     * "someFn(...get(String.fromCharCode(110))...)" and take {@code someFn}.
+     */
+    @Nonnull
+    private static String getDeobfuscationFunctionNameFallback(
+            @Nonnull final String javaScriptPlayerCode) throws ParsingException {
+        // 1) Try a direct string "n" access
+        final Pattern callWithLiteralN = Pattern.compile(
+                "(?:^|[^\\w$])([\\w$]+)\\([^\\n]{0,500}?\\.get\\(\\\"n\\\"\\)\\)",
+                Pattern.DOTALL);
+        Matcher m = callWithLiteralN.matcher(javaScriptPlayerCode);
+        if (m.find()) {
+            return m.group(1);
+        }
+
+        // 2) Try the common fromCharCode(110) variant (n)
+        final Pattern callWithCharCodeN = Pattern.compile(
+                "(?:^|[^\\w$])([\\w$]+)\\([^\\n]{0,800}?"
+                        + "String\\.fromCharCode\\(110\\)[^\\n]{0,200}?\\.get\\(",
+                Pattern.DOTALL);
+        m = callWithCharCodeN.matcher(javaScriptPlayerCode);
+        if (m.find()) {
+            return m.group(1);
+        }
+
+        throw new ParsingException("Could not find deobfuscation function with any of the known "
+                + "patterns in the base JavaScript player code");
+    }
+
     /**
      * Get the throttling parameter deobfuscation function name of YouTube's base JavaScript file.
      *
@@ -142,13 +183,16 @@ final class YoutubeThrottlingParameterUtils {
     @Nonnull
     static String getDeobfuscationFunctionName(@Nonnull final String javaScriptPlayerCode)
             throws ParsingException {
+        // Try fast-path regex patterns first
         final Matcher matcher;
         try {
             matcher = matchMultiplePatterns(DEOBFUSCATION_FUNCTION_NAME_REGEXES,
                     javaScriptPlayerCode);
         } catch (final Parser.RegexException e) {
-            throw new ParsingException("Could not find deobfuscation function with any of the "
-                    + "known patterns in the base JavaScript player code", e);
+            // Player code changes regularly. When none of the known patterns match, fall back to a
+            // slower but more resilient strategy: locate the throttling parameter in the code and
+            // extract the function name from the call site.
+            return getDeobfuscationFunctionNameFallback(javaScriptPlayerCode);
         }

         final String functionName = matcher.group(1);
